// Game state types
export const GameActionTypes = {
  START_GAME: 'START_GAME',
  END_GAME: 'END_GAME',
  UPDATE_SCORE: 'UPDATE_SCORE',
  UPDATE_TIME: 'UPDATE_TIME',
  SET_PLAYER_NAME: 'SET_PLAYER_NAME',
  SET_ROCKET: 'SET_ROCKET',
  UPDATE_INSTRUCTION: 'UPDATE_INSTRUCTION',
  TOGGLE_MUTE: 'TOGGLE_MUTE'
};

export const initialGameState = {
  isPlaying: false,
  score: 0,
  timeLeft: 60,
  playerName: '',
  selectedRocket: null,
  currentInstructionIndex: 0,
  isMuted: false,
  gameOver: false
};

export const gameReducer = (state, action) => {
  switch (action.type) {
    case GameActionTypes.START_GAME:
      return {
        ...state,
        isPlaying: true,
        score: 0,
        timeLeft: 60,
        gameOver: false
      };

    case GameActionTypes.END_GAME:
      return {
        ...state,
        isPlaying: false,
        gameOver: true
      };

    case GameActionTypes.UPDATE_SCORE:
      return {
        ...state,
        score: state.score + action.payload
      };

    case GameActionTypes.UPDATE_TIME:
      const newTime = state.timeLeft - 1;
      return {
        ...state,
        timeLeft: newTime,
        gameOver: newTime <= 0
      };

    case GameActionTypes.SET_PLAYER_NAME:
      return {
        ...state,
        playerName: action.payload
      };

    case GameActionTypes.SET_ROCKET:
      return {
        ...state,
        selectedRocket: action.payload
      };

    case GameActionTypes.UPDATE_INSTRUCTION:
      return {
        ...state,
        currentInstructionIndex: action.payload
      };

    case GameActionTypes.TOGGLE_MUTE:
      return {
        ...state,
        isMuted: !state.isMuted
      };

    default:
      return state;
  }
};
